const markStorefrontRevisionPublished = `-- name: MarkStorefrontRevisionPublished :exec
UPDATE storefront_revisions
SET status = 'published',
    published_at = $2
WHERE id = $1 AND status = 'draft'
`

type MarkStorefrontRevisionPublishedParams struct {
	ID          string             `json:"id"`
	PublishedAt pgtype.Timestamptz `json:"published_at"`
}

func (q *Queries) MarkStorefrontRevisionPublished(ctx context.Context, arg MarkStorefrontRevisionPublishedParams) error {
	_, err := q.db.Exec(ctx, markStorefrontRevisionPublished, arg.ID, arg.PublishedAt)
	return err
}

const nextStorefrontRevisionNumber = `-- name: NextStorefrontRevisionNumber :one
SELECT COALESCE(MAX(revision), 0)::int + 1 AS next
FROM storefront_revisions
WHERE store_id = $1
`

func (q *Queries) NextStorefrontRevisionNumber(ctx context.Context, storeID string) (int32, error) {
	row := q.db.QueryRow(ctx, nextStorefrontRevisionNumber, storeID)
	var next int32
	err := row.Scan(&next)
	return next, err
}

const productSlugExists = `-- name: ProductSlugExists :one
SELECT EXISTS (
    SELECT 1 FROM products
    WHERE store_id = $1 AND slug = $2 AND ($3::text = '' OR id <> $3)
) AS exists
`

type ProductSlugExistsParams struct {
	StoreID string `json:"store_id"`
	Slug    string `json:"slug"`
	Column3 string `json:"column_3"`
}

func (q *Queries) ProductSlugExists(ctx context.Context, arg ProductSlugExistsParams) (bool, error) {
	row := q.db.QueryRow(ctx, productSlugExists, arg.StoreID, arg.Slug, arg.Column3)
	var exists bool
	err := row.Scan(&exists)
	return exists, err
}

const updateProduct = `-- name: UpdateProduct :exec
UPDATE products
SET slug = $2,
    title = $3,
    short = $4,
    description = $5,
    price_idr = $6,
    type = $7,
    status = $8,
    version = $9,
    badge = $10,
    palette = $11,
    glyph = $12,
    includes = $13,
    allow_pwyt = $14,
    minimum_price_idr = $15,
    published_at = $16,
    updated_at = $17
WHERE id = $1 AND store_id = $18
`

type UpdateProductParams struct {
	ID              string             `json:"id"`
	Slug            string             `json:"slug"`
	Title           string             `json:"title"`
	Short           string             `json:"short"`
	Description     string             `json:"description"`
	PriceIdr        int64              `json:"price_idr"`
	Type            string             `json:"type"`
	Status          string             `json:"status"`
	Version         string             `json:"version"`
	Badge           string             `json:"badge"`
	Palette         string             `json:"palette"`
	Glyph           string             `json:"glyph"`
	Includes        []byte             `json:"includes"`
	AllowPwyt       bool               `json:"allow_pwyt"`
	MinimumPriceIdr *int64             `json:"minimum_price_idr"`
	PublishedAt     pgtype.Timestamptz `json:"published_at"`
	UpdatedAt       time.Time          `json:"updated_at"`
	StoreID         string             `json:"store_id"`
}

func (q *Queries) UpdateProduct(ctx context.Context, arg UpdateProductParams) error {
	_, err := q.db.Exec(ctx, updateProduct,
		arg.ID,
		arg.Slug,
		arg.Title,
		arg.Short,
		arg.Description,
		arg.PriceIdr,
		arg.Type,
		arg.Status,
		arg.Version,
		arg.Badge,
		arg.Palette,
		arg.Glyph,
		arg.Includes,
		arg.AllowPwyt,
		arg.MinimumPriceIdr,
		arg.PublishedAt,
		arg.UpdatedAt,
		arg.StoreID,
	)
	return err
}

